const employees = $input.all();
const results = [];
const today = new Date();

for (const item of employees) {
  const emp = item.json;

  if (emp.status !== 'active') continue;

  const leaveBalance = parseInt(emp.leaveBalance);
  const leaveTotal = parseInt(emp.leaveTotal);
  if (isNaN(leaveBalance) || isNaN(leaveTotal)) continue;
  if (leaveTotal <= 0) continue;
  if (leaveBalance < 0) continue;
  if (leaveBalance > leaveTotal) continue;
  if (leaveBalance === 0) continue;

  const hireDate = new Date(emp.hireDate);
  if (isNaN(hireDate.getTime())) continue;
  const tenureDays = Math.floor((today - hireDate) / (1000 * 60 * 60 * 24));
  if (tenureDays < 90) continue;

  const renewalDate = new Date(hireDate);
  renewalDate.setFullYear(today.getFullYear());
  if (renewalDate <= today) {
    renewalDate.setFullYear(today.getFullYear() + 1);
  }
  const daysUntilRenewal = Math.ceil((renewalDate - today) / (1000 * 60 * 60 * 24));
  const burnRate = leaveBalance / daysUntilRenewal;
  const usedPercentage = Math.round(((leaveTotal - leaveBalance) / leaveTotal) * 100);
  const renewalDateFormatted = renewalDate.toLocaleDateString('en-US', {
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  });

  let alertLevel = null;
  let alertEmoji = '';
  let urgency = '';

  if (burnRate >= 0.5) {
    alertLevel = 'critical';
    alertEmoji = '🔴';
    urgency = 'CRITICAL';
  } else if (burnRate >= 0.2) {
    alertLevel = 'warning';
    alertEmoji = '🟠';
    urgency = 'WARNING';
  } else if (burnRate >= 0.1) {
    alertLevel = 'low';
    alertEmoji = '🟡';
    urgency = 'LOW';
  } else {
    continue;
  }

  results.push({
    json: {
      id: emp.id,
      name: emp.name,
      email: emp.email,
      department: emp.department,
      hireDate: emp.hireDate,
      tenureDays: tenureDays,
      leaveBalance: leaveBalance,
      leaveTotal: leaveTotal,
      usedPercentage: usedPercentage,
      renewalDate: renewalDateFormatted,
      daysUntilRenewal: daysUntilRenewal,
      burnRate: Math.round(burnRate * 100) / 100,
      alertLevel: alertLevel,
      alertEmoji: alertEmoji,
      urgency: urgency
    }
  });
}

results.sort((a, b) => b.json.burnRate - a.json.burnRate);

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const emp = item.json;

  const templates = {
    critical: {
      subject: `Action Required: ${emp.leaveBalance} Leave Days Expiring on ${emp.renewalDate}`,
      body: `Hi ${emp.name},

This is a reminder that you currently have ${emp.leaveBalance} unused leave days out of your ${emp.leaveTotal} day annual entitlement.

Your leave balance will reset on ${emp.renewalDate} — that's ${emp.daysUntilRenewal} days from now. Any unused days will be forfeited after this date.

Action Required:
- Plan and book your remaining ${emp.leaveBalance} leave days before ${emp.renewalDate}
- Submit your time-off request through the HR portal
- Coordinate with your manager to agree on dates

Please make sure to use your entitled leave. Taking time off is important for your wellbeing and productivity.

If you have any questions, please reach out to your HR Business Partner.

Best regards,
HR Team`
    },
    warning: {
      subject: `Reminder: ${emp.leaveBalance} Leave Days Remaining — Expiring ${emp.renewalDate}`,
      body: `Hi ${emp.name},

You have ${emp.leaveBalance} leave days remaining out of your ${emp.leaveTotal} day annual entitlement.

Your leave balance resets on ${emp.renewalDate} (${emp.daysUntilRenewal} days away). Unused days will not carry over.

Action Required:
- Start planning your remaining ${emp.leaveBalance} days before ${emp.renewalDate}
- Submit your time-off request through the HR portal
- Align with your manager on preferred dates

We encourage you to take your well-deserved time off!

If you have any questions, please reach out to your HR Business Partner.

Best regards,
HR Team`
    },
    low: {
      subject: `Friendly Reminder: ${emp.leaveBalance} Leave Days Left Before ${emp.renewalDate}`,
      body: `Hi ${emp.name},

Just a quick reminder that you have ${emp.leaveBalance} leave days remaining before your balance resets on ${emp.renewalDate}.

Action Required:
- Book your remaining ${emp.leaveBalance} days before ${emp.renewalDate}
- Submit your request through the HR portal

If you have any questions, feel free to reach out to your HR Business Partner.

Best regards,
HR Team`
    }
  };

  const template = templates[emp.alertLevel];

  results.push({
    json: {
      id: emp.id,
      name: emp.name,
      email: emp.email,
      department: emp.department,
      leaveBalance: emp.leaveBalance,
      leaveTotal: emp.leaveTotal,
      renewalDate: emp.renewalDate,
      daysUntilRenewal: emp.daysUntilRenewal,
      alertLevel: emp.alertLevel,
      alertEmoji: emp.alertEmoji,
      urgency: emp.urgency,
      emailSubject: template.subject,
      emailBody: template.body
    }
  });
}

return results;

